var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니, 넌 여기 온 첫날에 봤던 그 교도관 끄나풀이잖아?","JPN":"って、あんたは初日に会った刑務官の手先じゃん。","ENG":"No, you're that officer's lackey I met on my first day here.","TWN":"不對，你是我被押到這裡的第一天遇到的那獄警的奸細？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"끄나풀이라뇨. 가이드입니다.","JPN":"手先って……ガイドですよ。","ENG":"Lackey? I am a guide, mind you.","TWN":"不是奸細，是小幫手。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그나저나, 엣지존에 수감된 죄수가 에이미 양이었습니까?","JPN":"それより、エッジゾーンに収容された囚人って、エイミーさんだったんですか？","ENG":"But I didn't know you were the prisoner held in the edge zone, Amy.","TWN":"話說被關進邊緣區域的囚犯竟然是艾米？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"이런 곳에 갇힐 정도로 위험한 사람처럼 보이진 않았는데요.","JPN":"こんなところに閉じ込められるほど危険な人には見えませんでしたけど。","ENG":"You didn't seem like someone so dangerous that you had to be locked up here.","TWN":"你看起來並不是一個危險人物呀。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"내 말이-","JPN":"あんたもそう思う？","ENG":"Tell me about it.","TWN":"就是說嘛。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"신원미상의 테러리스트다! 절대로 허튼 짓 할 틈을 줘선 안 돼! 라면서 자기들끼리 유난 떨더라니까?","JPN":"身元不明のテロリストだ！　余計なことをする隙を与えるな！　とか散々騒いでおいてさ。","ENG":"\\"An unidentified terrorist! Don't let her try anything!\\" is what they said as they make a big deal about everything.","TWN":"他們見到我就說什麼“身分不明的恐怖分子！我們不能讓她逍遙法外！”"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"딱히 사람을 세뇌시키는 능력 같은 거 없다고 했는데 들은 척도 안 하더니 사람 코빼기 하나 안 비추는 시커먼 방에 날 가둬 놓은 거라고.","JPN":"人を洗脳する能力なんてないって言ってるのに聞く耳も持たないで、人気のない黒い部屋にあたしを閉じ込めたの。","ENG":"I told them I didn't have any brainwashing powers, but they didn't listen and just locked me up in a room with no human contact whatsoever.","TWN":"我跟他們解釋我根本就沒有洗腦能力，但他們根本不聽，硬是把我關進了漆黑一片的房間裡。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"확실히… 조금 지나친 처사긴 하군요.","JPN":"確かに……少し度の過ぎた待遇ではありますね。","ENG":"It certainly is... a bit harsh.","TWN":"這個處罰確實有些……過分了。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"사람을 세뇌시키는 능력을 가졌단 이유만으로 사람을 이런 아무것도 없는 밀실에 가둬두다니.","JPN":"洗脳する能力があるという理由だけで、人をこんな何もない密室に閉じ込めるなんて。","ENG":"To lock someone up in an empty solitary cell just because they have brainwashing abilities.","TWN":"只是因為擁有洗腦能力，就把人家關進密室裡。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니, 그런 능력 없대도.","JPN":"いやだから、そんな能力持ってないってば。","ENG":"I just told you I don't have that ability.","TWN":"不，我說過沒那種能力。"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그나저나 여긴 어떻게 들어온 거야? 지금 죄수들끼리 폭동이라도 난 상황인가?","JPN":"それより、どうやってここに入ってきたの？　囚人同士で暴動とか？","ENG":"Besides, how did you come in here? Are the prisoners rioting?","TWN":"話說你是怎麼進入這裡的？囚犯們集體造反了不成？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니면 정말 네가 날 구해주러 온…","JPN":"それとも、本当にあんたがあたしを救いに……","ENG":"Or are you really here to save me–","TWN":"或者說你真的是來救我的白馬……"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"왜 네가 여기 있지?","JPN":"なぜ貴様がここにいる？","ENG":"Why are you here?","TWN":"你怎麼在這裡？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"Huh?","TWN":"蛤？"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…너!","JPN":"……あんた！","ENG":"...You!","TWN":"……你！"},"stage":{"bg":"PRISON_SPACE_02","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};